using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Get a configuration value by key.")]
    public static string GetConfigValue(
        [Description("The configuration key to look up (e.g. 'MaxRetries')")] string key)
    {
        var config = AppConfiguration.Current;
        return config.TryGetValue(key, out var value)
            ? $"{key} = {value}"
            : $"Key '{key}' not found. Available keys: {string.Join(", ", config.Keys)}";
    }

    [McpServerTool, Description("List all available configuration keys.")]
    public static string ListConfigKeys()
    {
        return string.Join("\n", AppConfiguration.Current.Keys.Order());
    }

    [McpServerTool, Description("Update a configuration value.")]
    public static string SetConfigValue(
        [Description("The configuration key to set")] string key,
        [Description("The new value")] string value)
    {
        AppConfiguration.Current[key] = value;
        return $"Updated {key} = {value}";
    }
}

using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"),
     Description("Returns the full application configuration as JSON.")]
    public static string GetAllSettings()
    {
        return JsonSerializer.Serialize(AppConfiguration.Current,
            new JsonSerializerOptions { WriteIndented = true });
    }

    [McpServerResource(UriTemplate = "config://app/environment", Name = "Environment Info",
        MimeType = "application/json"),
     Description("Returns current environment information.")]
    public static string GetEnvironmentInfo()
    {
        var info = new
        {
            MachineName = Environment.MachineName,
            OsVersion = Environment.OSVersion.ToString(),
            DotNetVersion = Environment.Version.ToString(),
            ProcessId = Environment.ProcessId,
            WorkingDirectory = Environment.CurrentDirectory
        };
        return JsonSerializer.Serialize(info,
            new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.Collections.Concurrent;

/// <summary>
/// Simple in-memory configuration store shared across tools and resources.
/// </summary>
public static class AppConfiguration
{
    public static ConcurrentDictionary<string, string> Current { get; } = new(
        new Dictionary<string, string>
        {
            ["MaxRetries"] = "3",
            ["TimeoutSeconds"] = "30",
            ["LogLevel"] = "Information",
            ["FeatureFlag.DarkMode"] = "true",
            ["ApiBaseUrl"] = "https://api.example.com"
        });
}

